// In-flight guard: prevents duplicate API calls from rapid button clicks.
let _sectionOpeningInFlight = false;

/**
 * Open the chatbot pre-loaded with an AI-generated section explanation.
 * US-258.5: Fires a real AI call via /api/chatbot/section-opening.
 * Falls back to static ctx.opening text if the API call fails.
 *
 * @param {string} sectionId - Key from AI_SECTION_CONTEXTS
 */
async function openChatbotWithSection(sectionId) {
    const ctx = AI_SECTION_CONTEXTS[sectionId];
    if (!ctx) {
        console.warn('ai-section-btn: unknown sectionId', sectionId);
        if (window.chatbotWidget) window.chatbotWidget.expand();
        return;
    }

    const widget = window.chatbotWidget;
    if (!widget) {
        console.warn('ai-section-btn: chatbotWidget not available');
        return;
    }

    // If already expanded with an active conversation, just focus input —
    // don't clobber an in-progress session.
    if (widget.state === 'expanded') {
        if (widget.input) widget.input.focus();
        return;
    }

    // Guard against multiple rapid clicks
    if (_sectionOpeningInFlight) return;
    _sectionOpeningInFlight = true;

    // Store section identity on the widget so follow-up API calls retain context
    widget.activeSectionId = sectionId;
    widget.activeSectionName = ctx.name;

    // Expand panel
    widget.expand();

    // Show typing indicator immediately so the panel is not blank during the API call
    setTimeout(() => widget.showTypingIndicator(), 150);

    try {
        const csrfToken = document.querySelector('meta[name="csrf-token"]')?.content || '';
        const resp = await fetch('/api/chatbot/section-opening', {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
                'X-CSRFToken': csrfToken,
            },
            body: JSON.stringify({ section_id: sectionId }),
        });

        widget.hideTypingIndicator();

        if (!resp.ok) {
            // API error — fall back to static opening
            widget.addSectionOpeningMessage(ctx.opening);
        } else {
            const data = await resp.json();
            const aiText = data.response || ctx.opening;
            widget.addSectionOpeningMessage(aiText);
        }
    } catch (_err) {
        // Network error — fall back to static opening
        widget.hideTypingIndicator();
        widget.addSectionOpeningMessage(ctx.opening);
    } finally {
        _sectionOpeningInFlight = false;
    }
}

// Wire up all buttons on DOMContentLoaded
document.addEventListener('DOMContentLoaded', () => {
    document.querySelectorAll('.ai-section-btn[data-section-id]').forEach(btn => {
        btn.addEventListener('click', () => {
            openChatbotWithSection(btn.dataset.sectionId);
        });
    });
});
